mapper.sql:
SELECT B.SUBSCRIBER_NO AS subscriberNo , B.SUB_LINK_NAME AS subLinkName , A.CONTRACT_NUM AS contractNum , A.INSR_PROD_CD AS insrProdCd , FN_GET_RATENM(A.INSR_PROD_CD) AS insrProdNm , A.STRT_DTTM AS strtDttm , A.END_DTTM AS endDttm , A.INSR_STAT_CD AS insrStatCd , FN_GET_CODENM('CMN0251', A.INSR_STAT_CD) AS insrStatNm , A.MODEL_NM AS modelNm , A.INTM_SRL_NO AS intmSrlNo , A.MODEL_ID AS modelId , A.CHN_CD AS chnCd , FN_GET_CODENM('CMN0249', A.CHN_CD) AS chnNm , C.REQ_BUY_TYPE AS reqBuyType , FN_GET_CODENM('RCP9004', C.REQ_BUY_TYPE) AS reqBuyTypeNm , B.SCAN_ID AS scanId , C.RES_NO AS resNo , B.OPEN_AGNT_CD AS openAgntCd , FN_GET_ORGNM(B.OPEN_AGNT_CD) AS openAgntNm , A.INSR_MNGM_NO AS insrMngmNo , NVL(A.RMN_CMPN_AMT, D.CMPN_LMT_AMT) AS rmnCmpnAmt , A.CAN_RSLT_CD AS canRsltCd , FN_GET_CODENM('CMN0252', A.CAN_RSLT_CD) AS canRsltNm , D.CMPN_LMT_AMT AS cmpnLmtAmt , D.INSR_ENGG_CNT AS insrEnggCnt , A.REQ_IN_DAY AS reqinday /* 신청일자 */ FROM MSP_INTM_INSR_MEMBER A , MSP_JUO_SUB_INFO B , MSP_REQUEST_DTL C , MSP_INTM_INSR_MST D WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.CONTRACT_NUM = C.CONTRACT_NUM AND A.INSR_PROD_CD = D.INSR_PROD_CD
AND A.REQ_IN_DAY BETWEEN #{searchFromDt} || '000000' AND #{searchToDt} || '235959'
AND A.STRT_DTTM BETWEEN #{searchFromDt} || '000000' AND #{searchToDt} || '235959'
AND A.INSR_PROD_CD = #{insrProdCd}
AND C.REQ_BUY_TYPE = #{reqBuyType}
AND A.INSR_STAT_CD = #{insrStatCd}
AND B.CONTRACT_NUM = #{searchVal}
AND B.SUB_LINK_NAME LIKE #{searchVal} || '%'
AND B.SUBSCRIBER_NO = REPLACE(#{searchVal},'-')
AND B.OPEN_AGNT_CD = #{agntId}
ORDER BY A.STRT_DTTM, B.SUB_LINK_NAME

mapper.select:
/* InsrMemberMapper.getIntmInsrOrderYn */
SELECT	DECODE(COUNT(1), 0, 'N', 'Y') UPD_YN
FROM	MSP_INTM_INSR_ORDER
WHERE	CONTRACT_NUM = #{contractNum}
AND		INSR_PROD_CD = #{insrProdCd}
AND		STRT_DTTM = #{strtDt}
AND		IF_TRGT_CD IN ('N', 'Y')

mapper.update:
/* InsrOrderMapper.updMspIntmInsrOrder */
UPDATE MSP_INTM_INSR_ORDER
SET		IF_TRGT_CD = 'C'
		, END_DTTM = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
		, RVISN_ID = #{sessionUserId}
		, RVISN_DTTM = SYSDATE
WHERE	CONTRACT_NUM = #{contractNum}
AND		INSR_PROD_CD = #{insrProdCd}
AND		STRT_DTTM = #{strtDt}
